const readline = require('readline');
const chalk = require('chalk');
const fs = require('fs-extra');
const path = require('path');

const GameEngine = require('./engine/GameEngine');
const Player = require('./entities/Player');
const Story = require('./story/Story');

const SAVE_FILE = path.join(__dirname, '../savegame.json');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

async function main() {
    console.clear();
    console.log(chalk.cyan.bold('\n========================================'));
    console.log(chalk.yellow.bold('     🗡️  {{project_name}}  🗡️'));
    console.log(chalk.cyan.bold('========================================\n'));

    let player = null;
    let gameEngine = null;

    // Check for save file
    if (await fs.pathExists(SAVE_FILE)) {
        const choice = await askQuestion('Load saved game? (y/n): ');
        if (choice.toLowerCase() === 'y') {
            try {
                const saveData = await fs.readJson(SAVE_FILE);
                player = Player.fromJSON(saveData.player);
                console.log(chalk.green('\n✓ Game loaded!\n'));
            } catch (err) {
                console.log(chalk.red('\n✗ Failed to load save file. Starting new game.\n'));
            }
        }
    }

    if (!player) {
        // New game
        const name = await askQuestion('Enter your character name: ');
        player = new Player(name || 'Hero');
        console.log(chalk.green(`\n✓ Welcome, ${player.name}! Your adventure begins...\n`));
        await wait(1000);
    }

    gameEngine = new GameEngine(player, rl);
    await gameEngine.start();
}

function askQuestion(question) {
    return new Promise((resolve) => {
        rl.question(chalk.cyan(question), (answer) => {
            resolve(answer.trim());
        });
    });
}

function wait(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

// Handle graceful exit
process.on('SIGINT', () => {
    console.log(chalk.yellow('\n\nThanks for playing!'));
    rl.close();
    process.exit(0);
});

main().catch(err => {
    console.error(chalk.red('Error:'), err);
    rl.close();
    process.exit(1);
});

