const chalk = require('chalk');
const fs = require('fs-extra');
const path = require('path');

const CombatSystem = require('./CombatSystem');
const InventoryManager = require('./InventoryManager');
const Story = require('../story/Story');

const SAVE_FILE = path.join(__dirname, '../../savegame.json');

class GameEngine {
    constructor(player, rl) {
        this.player = player;
        this.rl = rl;
        this.combat = new CombatSystem(player);
        this.inventory = new InventoryManager(player);
        this.story = new Story();
        this.gameState = 'exploring'; // exploring, combat, shop, dialog
        this.currentLocation = 'village';
        this.running = true;
    }

    async start() {
        while (this.running) {
            console.clear();
            this.displayStatus();

            if (this.gameState === 'exploring') {
                await this.explore();
            } else if (this.gameState === 'combat') {
                await this.combatLoop();
            } else if (this.gameState === 'shop') {
                await this.shopLoop();
            }
        }
    }

    displayStatus() {
        console.log(chalk.cyan.bold('╔══════════════════════════════════════╗'));
        console.log(chalk.cyan.bold('║') + ` ${this.player.name} - Level ${this.player.level}`.padEnd(37) + chalk.cyan.bold('║'));
        console.log(chalk.cyan.bold('╠══════════════════════════════════════╣'));
        console.log(chalk.cyan.bold('║') + ` HP: ${this.getHealthBar()} ${this.player.hp}/${this.player.maxHp}`.padEnd(37) + chalk.cyan.bold('║'));
        console.log(chalk.cyan.bold('║') + ` XP: ${this.player.xp}/${this.player.xpToNext} | Gold: ${this.player.gold}💰`.padEnd(37) + chalk.cyan.bold('║'));
        console.log(chalk.cyan.bold('║') + ` Location: ${this.currentLocation}`.padEnd(37) + chalk.cyan.bold('║'));
        console.log(chalk.cyan.bold('╚══════════════════════════════════════╝\n'));
    }

    getHealthBar() {
        const percent = this.player.hp / this.player.maxHp;
        const filled = Math.round(percent * 10);
        const empty = 10 - filled;
        const bar = '█'.repeat(filled) + '░'.repeat(empty);
        return percent > 0.5 ? chalk.green(bar) : percent > 0.25 ? chalk.yellow(bar) : chalk.red(bar);
    }

    async explore() {
        console.log(chalk.magenta(`\n📍 You are in the ${this.currentLocation}.`));
        console.log(chalk.gray(this.story.getLocationDescription(this.currentLocation)));
        console.log(chalk.yellow('\nWhat would you like to do?'));
        console.log(chalk.white('1. Explore the area'));
        console.log(chalk.white('2. Check inventory'));
        console.log(chalk.white('3. Rest and heal'));
        console.log(chalk.white('4. Visit shop'));
        console.log(chalk.white('5. Travel to...'));
        console.log(chalk.white('6. Save game'));
        console.log(chalk.white('7. Quit'));

        const choice = await this.ask('\nChoice: ');

        switch(choice) {
            case '1':
                await this.exploreArea();
                break;
            case '2':
                this.inventory.display();
                await this.waitForKey();
                break;
            case '3':
                await this.rest();
                break;
            case '4':
                this.gameState = 'shop';
                break;
            case '5':
                await this.travel();
                break;
            case '6':
                await this.saveGame();
                break;
            case '7':
                this.running = false;
                console.log(chalk.yellow('\nThanks for playing!'));
                break;
            default:
                console.log(chalk.red('Invalid choice!'));
                await this.wait(1000);
        }
    }

    async exploreArea() {
        const roll = Math.random();

        if (roll < 0.4) {
            // Combat encounter
            const enemy = this.combat.generateEnemy(this.player.level, this.currentLocation);
            console.log(chalk.red(`\n⚔️  A wild ${enemy.name} appears!`));
            await this.wait(1000);
            this.gameState = 'combat';
            this.currentEnemy = enemy;
        } else if (roll < 0.7) {
            // Find item
            const item = this.inventory.generateRandomItem();
            console.log(chalk.green(`\n✨ You found: ${item.name}!`));
            this.player.inventory.push(item);
            await this.wait(1500);
        } else {
            // Nothing
            console.log(chalk.gray('\n...You explore but find nothing interesting.'));
            await this.wait(1500);
        }
    }

    async combatLoop() {
        const result = await this.combat.fight(this.currentEnemy, this.rl);

        if (result === 'victory') {
            this.player.gainXp(this.currentEnemy.xpReward);
            this.player.gold += this.currentEnemy.goldReward;
            console.log(chalk.green(`\n💰 You gained ${this.currentEnemy.xpReward} XP and ${this.currentEnemy.goldReward} gold!`));
        } else if (result === 'defeat') {
            console.log(chalk.red('\n💀 You have been defeated!'));
            console.log(chalk.yellow('You wake up in the village, weakened...'));
            this.player.hp = 1;
            this.currentLocation = 'village';
            await this.wait(2000);
        }

        this.currentEnemy = null;
        this.gameState = 'exploring';
        await this.wait(2000);
    }

    async shopLoop() {
        console.clear();
        console.log(chalk.cyan.bold('\n🏪 WELCOME TO THE SHOP 🏪\n'));

        const items = [
            { name: 'Health Potion', price: 20, type: 'consumable', heal: 50 },
            { name: 'Iron Sword', price: 100, type: 'weapon', damage: 10 },
            { name: 'Leather Armor', price: 80, type: 'armor', defense: 5 },
            { name: 'Strength Elixir', price: 50, type: 'consumable', str: 2 }
        ];
\        console.log(chalk.yellow(`Your gold: ${this.player.gold}💰\n`));
        console.log(chalk.white('Items for sale:'));
        items.forEach((item, i) => {
            console.log(chalk.white(`${i + 1}. ${item.name} - ${item.price}💰`));
        });
        console.log(chalk.white('5. Leave shop'));

        const choice = await this.ask('\nChoice: ');
        const index = parseInt(choice) - 1;

        if (choice === '5') {
            this.gameState = 'exploring';
        } else if (items[index]) {
            const item = items[index];
            if (this.player.gold >= item.price) {
                this.player.gold -= item.price;
                this.player.inventory.push({...item, id: Date.now()});
                console.log(chalk.green(`\n✓ Purchased ${item.name}!`));
            } else {
                console.log(chalk.red('\n✗ Not enough gold!'));
            }
            await this.wait(1500);
        }
    }

    async travel() {
        const locations = ['village', 'forest', 'dungeon', 'mountain'];
        console.log(chalk.yellow('\nWhere would you like to go?'));
        locations.forEach((loc, i) => {
            if (loc !== this.currentLocation) {
                console.log(chalk.white(`${i + 1}. ${loc.charAt(0).toUpperCase() + loc.slice(1)}`));
            }
        });

        const choice = await this.ask('\nChoice: ');
        const location = locations[parseInt(choice) - 1];

        if (location && location !== this.currentLocation) {
            console.log(chalk.cyan(`\n🚶 Traveling to ${location}...`));
            await this.wait(2000);
            this.currentLocation = location;
        }
    }

    async rest() {
        if (this.player.hp >= this.player.maxHp) {
            console.log(chalk.yellow('\nYou are already at full health!'));
        } else {
            const heal = Math.floor(this.player.maxHp * 0.5);
            this.player.hp = Math.min(this.player.hp + heal, this.player.maxHp);
            console.log(chalk.green(`\n💤 You rest and recover ${heal} HP!`));
        }
        await this.wait(1500);
    }

    async saveGame() {
        try {
            await fs.writeJson(SAVE_FILE, {
                player: this.player.toJSON(),
                location: this.currentLocation,
                savedAt: new Date().toISOString()
            });
            console.log(chalk.green('\n✓ Game saved successfully!'));
        } catch (err) {
            console.log(chalk.red('\n✗ Failed to save game!'));
        }
        await this.wait(1500);
    }

    ask(question) {
        return new Promise((resolve) => {
            this.rl.question(chalk.cyan(question), (answer) => {
                resolve(answer.trim());
            });
        });
    }

    waitForKey() {
        return this.ask(chalk.gray('\nPress Enter to continue...'));
    }

    wait(ms) {
        return new Promise(resolve => setTimeout(resolve, ms));
    }
}

module.exports = GameEngine;

