const chalk = require('chalk');

class CombatSystem {
    constructor(player) {
        this.player = player;
    }

    generateEnemy(playerLevel, location) {
        const enemies = {
            village: [
                { name: 'Slime', hp: 20, damage: 5, xpReward: 10, goldReward: 5 },
                { name: 'Rat', hp: 15, damage: 4, xpReward: 8, goldReward: 3 }
            ],
            forest: [
                { name: 'Wolf', hp: 40, damage: 10, xpReward: 25, goldReward: 15 },
                { name: 'Bandit', hp: 50, damage: 12, xpReward: 30, goldReward: 20 }
            ],
            dungeon: [
                { name: 'Skeleton', hp: 60, damage: 15, xpReward: 40, goldReward: 25 },
                { name: 'Orc', hp: 80, damage: 20, xpReward: 60, goldReward: 40 }
            ],
            mountain: [
                { name: 'Troll', hp: 120, damage: 25, xpReward: 100, goldReward: 70 },
                { name: 'Dragon Whelp', hp: 150, damage: 30, xpReward: 150, goldReward: 100 }
            ]
        };

        const pool = enemies[location] || enemies.village;
        const base = pool[Math.floor(Math.random() * pool.length)];

        // Scale enemy to player level
        const levelScale = 1 + (playerLevel - 1) * 0.2;

        return {
            ...base,
            maxHp: Math.floor(base.hp * levelScale),
            hp: Math.floor(base.hp * levelScale),
            damage: Math.floor(base.damage * levelScale),
            xpReward: Math.floor(base.xpReward * levelScale),
            goldReward: Math.floor(base.goldReward * levelScale)
        };
    }

    async fight(enemy, rl) {
        console.clear();
        console.log(chalk.red.bold('\n⚔️  COMBAT STARTED ⚔️\n'));

        while (this.player.hp > 0 && enemy.hp > 0) {
            this.displayCombatStatus(enemy);

            console.log(chalk.yellow('\nYour turn:'));
            console.log(chalk.white('1. Attack'));
            console.log(chalk.white('2. Use item'));
            console.log(chalk.white('3. Flee'));

            const choice = await this.ask(rl, 'Choice: ');

            switch(choice) {
                case '1':
                    await this.playerAttack(enemy);
                    break;
                case '2':
                    await this.useItem(rl);
                    continue;
                case '3':
                    if (Math.random() < 0.5) {
                        console.log(chalk.yellow('\n🏃 You fled successfully!'));
                        await this.wait(1500);
                        return 'fled';
                    } else {
                        console.log(chalk.red('\n❌ Failed to flee!'));
                    }
                    break;
                default:
                    console.log(chalk.red('Invalid choice!'));
            }

            if (enemy.hp <= 0) {
                console.log(chalk.green(`\n🎉 You defeated the ${enemy.name}!`));
                await this.wait(1500);
                return 'victory';
            }

            // Enemy turn
            await this.enemyAttack(enemy);

            if (this.player.hp <= 0) {
                return 'defeat';
            }

            await this.wait(1500);
        }
    }

    displayCombatStatus(enemy) {
        const enemyPercent = enemy.hp / enemy.maxHp;
        const enemyBar = '█'.repeat(Math.round(enemyPercent * 10)) + '░'.repeat(10 - Math.round(enemyPercent * 10));

        console.log(chalk.red.bold(`${enemy.name}`));
        console.log(chalk.red(`HP: ${enemyBar} ${enemy.hp}/${enemy.maxHp}\n`));
    }

    async playerAttack(enemy) {
        const damage = Math.floor(this.player.getAttackDamage() * (0.8 + Math.random() * 0.4));
        enemy.hp -= damage;
        console.log(chalk.green(`\n⚔️  You dealt ${damage} damage!`));
    }

    async enemyAttack(enemy) {
        console.log(chalk.yellow(`\n👹 ${enemy.name} attacks!`));
        await this.wait(500);

        const damage = Math.max(1, enemy.damage - this.player.getDefense());
        this.player.hp -= damage;
        console.log(chalk.red(`💥 You took ${damage} damage!`));
    }

    async useItem(rl) {
        const consumables = this.player.inventory.filter(item => item.type === 'consumable');

        if (consumables.length === 0) {
            console.log(chalk.yellow('\nNo consumable items!'));
            await this.wait(1000);
            return;
        }

        console.log(chalk.yellow('\nSelect item to use:'));
        consumables.forEach((item, i) => {
            console.log(chalk.white(`${i + 1}. ${item.name}`));
        });
        console.log(chalk.white('0. Cancel'));

        const choice = await this.ask(rl, 'Choice: ');
        const index = parseInt(choice) - 1;

        if (consumables[index]) {
            const item = consumables[index];

            if (item.heal) {
                const heal = Math.min(item.heal, this.player.maxHp - this.player.hp);
                this.player.hp += heal;
                console.log(chalk.green(`\n💚 Used ${item.name}! Healed ${heal} HP!`));
            }
            if (item.str) {
                this.player.strength += item.str;
                console.log(chalk.green(`\n💪 Used ${item.name}! Strength +${item.str}!`));
            }

            // Remove item
            const invIndex = this.player.inventory.indexOf(item);
            this.player.inventory.splice(invIndex, 1);
            await this.wait(1500);
        }
    }

    ask(rl, question) {
        return new Promise((resolve) => {
            rl.question(chalk.cyan(question), (answer) => {
                resolve(answer.trim());
            });
        });
    }

    wait(ms) {
        return new Promise(resolve => setTimeout(resolve, ms));
    }
}

module.exports = CombatSystem;

