const chalk = require('chalk');

class InventoryManager {
    constructor(player) {
        this.player = player;
    }

    display() {
        console.clear();
        console.log(chalk.cyan.bold('\n🎒 INVENTORY 🎒\n'));

        if (this.player.inventory.length === 0) {
            console.log(chalk.gray('Your inventory is empty.'));
            return;
        }

        // Group items by type
        const weapons = this.player.inventory.filter(i => i.type === 'weapon');
        const armors = this.player.inventory.filter(i => i.type === 'armor');
        const consumables = this.player.inventory.filter(i => i.type === 'consumable');

        if (weapons.length > 0) {
            console.log(chalk.yellow('Weapons:'));
            weapons.forEach(item => {
                console.log(chalk.white(`  • ${item.name} (+${item.damage} ATK)`));
            });
        }

        if (armors.length > 0) {
            console.log(chalk.yellow('\nArmor:'));
            armors.forEach(item => {
                console.log(chalk.white(`  • ${item.name} (+${item.defense} DEF)`));
            });
        }

        if (consumables.length > 0) {
            console.log(chalk.yellow('\nConsumables:'));
            const grouped = this.groupConsumables(consumables);
            for (let [name, items] of Object.entries(grouped)) {
                console.log(chalk.white(`  • ${name} x${items.length}`));
            }
        }

        console.log(chalk.cyan(`\n💰 Gold: ${this.player.gold}`));
    }

    groupConsumables(items) {
        const grouped = {};
        for (let item of items) {
            if (!grouped[item.name]) grouped[item.name] = [];
            grouped[item.name].push(item);
        }
        return grouped;
    }

    generateRandomItem() {
        const items = [
            { name: 'Health Potion', type: 'consumable', heal: 30, rarity: 'common' },
            { name: 'Greater Health Potion', type: 'consumable', heal: 60, rarity: 'uncommon' },
            { name: 'Rusty Sword', type: 'weapon', damage: 3, rarity: 'common' },
            { name: 'Iron Dagger', type: 'weapon', damage: 5, rarity: 'common' },
            { name: 'Leather Boots', type: 'armor', defense: 2, rarity: 'common' },
            { name: 'Gold Coin', type: 'currency', value: 10, rarity: 'common' }
        ];

        const rarityRoll = Math.random();
        let rarity = 'common';
        if (rarityRoll > 0.9) rarity = 'rare';
        else if (rarityRoll > 0.7) rarity = 'uncommon';

        const pool = items.filter(i => i.rarity === rarity);
        const baseItem = pool[Math.floor(Math.random() * pool.length)] || items[0];

        return {...baseItem, id: Date.now()};
    }
}

module.exports = InventoryManager;

