class Player {
    constructor(name) {
        this.name = name;
        this.level = 1;
        this.xp = 0;
        this.xpToNext = 100;
        this.hp = 100;
        this.maxHp = 100;
        this.strength = 10;
        this.defense = 5;
        this.gold = 50;
        this.inventory = [];
        this.equippedWeapon = null;
        this.equippedArmor = null;
    }

    getAttackDamage() {
        let damage = this.strength;
        if (this.equippedWeapon) {
            damage += this.equippedWeapon.damage;
        }
        return damage;
    }

    getDefense() {
        let def = this.defense;
        if (this.equippedArmor) {
            def += this.equippedArmor.defense;
        }
        return def;
    }

    gainXp(amount) {
        this.xp += amount;
        if (this.xp >= this.xpToNext) {
            this.levelUp();
        }
    }

    levelUp() {
        this.level++;
        this.xp -= this.xpToNext;
        this.xpToNext = Math.floor(this.xpToNext * 1.5);
        this.maxHp += 20;
        this.hp = this.maxHp;
        this.strength += 3;
        this.defense += 2;
        console.log(`\n⭐ LEVEL UP! You are now level ${this.level}!`);
    }

    toJSON() {
        return {
            name: this.name,
            level: this.level,
            xp: this.xp,
            xpToNext: this.xpToNext,
            hp: this.hp,
            maxHp: this.maxHp,
            strength: this.strength,
            defense: this.defense,
            gold: this.gold,
            inventory: this.inventory,
            equippedWeapon: this.equippedWeapon,
            equippedArmor: this.equippedArmor
        };
    }

    static fromJSON(data) {
        const player = new Player(data.name);
        Object.assign(player, data);
        return player;
    }
}

module.exports = Player;

